  ASSERT_TRUE(ir != NULL && ir->funcs != NULL);
  ASSERT_TRUE(count_ir_op(ir->funcs, IR_MUL) >= 1);
  ASSERT_TRUE(count_ir_op(ir->funcs, IR_ZEXT) >= 1);
  ASSERT_EQ(1, count_ir_op(ir->funcs, IR_RET));
